set-payload.value:
#[%dw 2.0
output application/json
var u = vars.dbUser
---
{
  token: "mtis-" ++ ((u.id as String) splitBy "-") joinBy "",
  user: { id: u.id, name: u.name, email: u.email, role: u.role }
}]

#[%dw 2.0
output application/json
var cid = attributes.uriParams.courseId
---
{
  courseId: cid,
  questions: [
    { id: 'q1', text: '¿Qué significa SOA?', options: ['Arquitectura orientada a servicios','Solo Oracle Apps','Un lenguaje'] , correct: 'q1-A' },
    { id: 'q2', text: 'Ventaja principal de REST', options: ['Simplicidad y escalabilidad','Solo XML','Sin HTTP'] , correct: 'q2-A' },
    { id: 'q3', text: 'Rol típico de un ESB', options: ['Mediación y orquestación','Solo UI','Almacenamiento OLAP'] , correct: 'q3-A' }
  ]
}]

#[%dw 2.0
output application/java
var answers = vars.req.answers default []
var correct = ['q1-A','q2-A','q3-A']
var selected = answers map ((a) -> a.questionId ++ '-' ++ (a.selected default ''))
var hits = sizeOf((correct filter (c) -> selected contains c))
var total = sizeOf(correct)
var grade = if (total == 0) 0 else (hits * 10) / total
---
{ grade: grade, passed: grade >= 5, hits: hits, total: total }]
